      {{ "type": "action", "description": "กรอกรหัสผ่านในช่องสำหรับเข้าสู่ระบบ" }},
      {{ "type": "validation", "description": "กดเข้าสู่ระบบ แล้วตรวจสอบว่ามีการเปลี่ยนหน้า/แสดงสถานะการเข้าสู่ระบบสำเร็จ" }}
