      {{ "type": "validation", "description": "ตั้งขนาดหน้าจอแบบแท็บเล็ต แล้วตรวจว่ายังเห็นเนื้อหาหลัก" }},
      {{ "type": "validation", "description": "ตั้งขนาดหน้าจอแบบมือถือ แล้วตรวจว่ายังเห็นเนื้อหาหลัก" }}
